    Student* st;
    struct Nod *next, *prev;
} Nod;

typedef struct {
    struct Nod *p, *u;
} lst;

lst functie(lst l, Student *pStd) {
    Nod *nou;
    nou = (Nod*)malloc(sizeof(Nod));
    nou->st = pStd;
    nou->next = 0;
    nou->prev = l.u;
