typedef struct {
    int id;
    char* nume;
    float medie;
} Student;

typedef struct {
    Student st;
    struct Nod* next;
} Nod;

Nod* f1(Nod *p, Student s) {
    Nod* nou;
    nou = (Nod*)malloc(1 * sizeof(Nod));
    nou->st.id = s.id;
    nou->st.nume = (char*)malloc((strlen(s.nume) + 1) * sizeof(char));
    strcpy(nou->st.nume, s.nume);
    nou->next = p;
    return nou;
}

int f2(char* str, int s) {
    int temp = 0, poz;
    for(int i = 0; i < strlen(str); i++)
        temp += str[i];
    poz = temp % s;
    return poz;
}

void f3(Nod** x, Student s, int st) {
    int k;
    k = f2(s.nume, st);
    x[k] = f1(x[k], s);
}

